SELECT /*ReviewMapper.selectMcashReviewTotalCnt 사용후기 리스트용 COUNT  */
COUNT(1) AS CNT
FROM NMCP_REVIEW_MST
WHERE 1=1

    AND USE_YN = #{useYn}


    AND REVIEW_TYPE = #{reviewType}


    AND REVIEW_TYPE_DTL = #{reviewTypeDtl}


    AND NOTI_YN = #{notiYn}


    AND CONTRACT_NUM IN

        #{item}



    AND CONTRACT_NUM = #{contractNum}


    AND BEST_YN = 'Y'


    AND SNS_INFO IS NOT NULL

SELECT /*ReviewMapper.selectReviewListByNoti 사용후기 공지 리스트 */ r.REVIEW_SEQ , r.REVIEW_TYPE , r.REVIEW_TYPE_DTL , r.CONTRACT_NUM , r.NOTI_YN , r.BEST_YN , r.USE_YN , r.PRIZE_RNK , r.REVIEW_CONTENT , r.SNS_INFO , r.REGST_NM , r.REGST_DTTM , ADD_MONTHS(SYSDATE, -3) AS baseDate FROM ( SELECT REVIEW_SEQ , REVIEW_TYPE , REVIEW_TYPE_DTL , CONTRACT_NUM , NOTI_YN , BEST_YN , USE_YN , PRIZE_RNK , REVIEW_CONTENT , SNS_INFO , REGST_NM , REGST_DTTM FROM NMCP_REVIEW_MST) r WHERE NOTI_YN = 'Y' AND USE_YN = 'Y'
AND REVIEW_TYPE = #{reviewType}
AND REVIEW_TYPE_DTL = #{reviewTypeDtl}
AND CONTRACT_NUM IN
#{item}
AND BEST_YN = 'Y'
AND SNS_INFO IS NOT NULL
UNION ALL
SELECT /*ReviewMapper.selectReviewListByNoti 사용후기 공지 리스트 */ rv.REVIEW_SEQ , rv.REVIEW_TYPE , rv.REVIEW_TYPE_DTL , rv.CONTRACT_NUM , rv.NOTI_YN , rv.BEST_YN , rv.USE_YN , rv.PRIZE_RNK , rv.REVIEW_CONTENT , rv.SNS_INFO , rv.REGST_NM , rv.REGST_DTTM , ADD_MONTHS(SYSDATE, -3) AS baseDate FROM ( SELECT REVIEW_SEQ , REVIEW_TYPE , REVIEW_TYPE_DTL , CONTRACT_NUM , NOTI_YN , BEST_YN , USE_YN , PRIZE_RNK , REVIEW_CONTENT , SNS_INFO , REGST_NM , REGST_DTTM FROM NMCP_REVIEW_MST ORDER BY REGST_DTTM DESC) rv WHERE NOTI_YN != 'Y'
AND USE_YN = #{useYn}
AND REVIEW_TYPE = #{reviewType}
AND REVIEW_TYPE_DTL = #{reviewTypeDtl}
AND CONTRACT_NUM IN
#{item}
AND BEST_YN = 'Y'
AND SNS_INFO IS NOT NULL

SELECT /*ReviewMapper.selectReviewImgList 사용후기 리스트 이미지 */ REVIEW_SEQ , IMG_SEQ , FILE_PATH_NM , FILE_TYPE , FILE_CAPA , FILE_ALT FROM NMCP_REVIEW_IMG WHERE REVIEW_SEQ = #{reviewSeq}
AND IMG_SEQ = #{imgSeq}
ORDER BY IMG_SEQ

