    SELECT SQ_REVIEW_MST.NEXTVAL FROM DUAL

INSERT INTO NMCP_REVIEW_MST (
    REVIEW_SEQ
    , REVIEW_TYPE
    , REVIEW_TYPE_DTL
    , CONTRACT_NUM
    , USERID
    , NOTI_YN
    , BEST_YN
    , USE_YN
    , PRIZE_RNK
    , REVIEW_CONTENT
    , SNS_INFO
    , RIP
    , REGST_NM
    , REGST_ID
    , REGST_DTTM
) VALUES (
    #{reviewSeq}
    , #{reviewType}
    , #{reviewTypeDtl}
    , #{contractNum}
    , #{userId}
    , #{notiYn}
    , #{bestYn}
    , #{useYn}
    , #{prizeRnk}
    , #{reviewContent}
    , #{snsInfo}
    , #{rIp}
    , #{regstNm}
    , #{regstId}
    , SYSDATE
 )

INSERT INTO NMCP_REVIEW_IMG (
    REVIEW_SEQ
    , IMG_SEQ
    , FILE_PATH_NM
    , FILE_TYPE
    , FILE_CAPA
    , FILE_ALT
    , REGST_ID
    , REGST_DTTM
) VALUES (
    #{reviewSeq}
    , #{imgSeq}
    , #{filePathNm}
    , #{fileType}
    , #{fileCapa}
    , #{fileAlt}
    , #{regstId}
    , SYSDATE
)
